--
-- Name: warehouse_loans; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.warehouse_loans (
    id bigint NOT NULL,
    resource_id bigint NOT NULL,
    quantity integer NOT NULL,
    from_warehouse_id bigint,
    from_temporary_warehouse_id bigint,
    to_warehouse_id bigint,
    to_temporary_warehouse_id bigint,
    borrowed_at date DEFAULT CURRENT_DATE NOT NULL,
    due_date date,
    returned_at date,
    returned_quantity integer DEFAULT 0 NOT NULL,
    status character varying(32) DEFAULT 'Outstanding'::character varying NOT NULL,
    notes text,
    created_by bigint,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT warehouse_loans_from_one_store CHECK (((((from_warehouse_id IS NOT NULL))::integer + ((from_temporary_warehouse_id IS NOT NULL))::integer) = 1)),
    CONSTRAINT warehouse_loans_quantity_check CHECK ((quantity > 0)),
    CONSTRAINT warehouse_loans_to_one_store CHECK (((((to_warehouse_id IS NOT NULL))::integer + ((to_temporary_warehouse_id IS NOT NULL))::integer) = 1))
);


--
