17	capabilities	capabilities.items	[{"title":"Early Warning System","icon":"fa-satellite-dish","color":"#ef4444","link":"/m/preparedness/early-warnings","description":"Multi-hazard early warning with automated SMS, email, and WhatsApp alerts to communities at risk."},{"title":"GIS Mapping","icon":"fa-map-marked-alt","color":"#60a5fa","link":"/m/prevention-mitigation/risk-mapping","description":"Interactive geospatial mapping of hazards, risks, resources, and evacuation routes across all regions."},{"title":"Incident Management","icon":"fa-tasks","color":"#4ade80","description":"End-to-end incident tracking from initial report through response coordination to recovery programs.","detail":"How it works in the system: a citizen or field officer reports an incident (from this portal or the app). It is reviewed up the chain — District Coordinator → DAS → Regional Coordinator → RAS → Assistant Director → Director. Once approved, the EOCC coordinates the response: tasks are assigned, resources dispatched from the nearest warehouses, and progress tracked until recovery programmes close the incident."},{"title":"Resource Management","icon":"fa-warehouse","color":"#60a5fa","description":"Track warehouses, inventory, and allocated resources for rapid deployment during emergencies.","detail":"How it works in the system: zonal and temporary warehouses keep a live stock ledger (food, shelter, rescue equipment). When an incident is approved, responders request allocations; approvals dispatch stock with movement tracking, and every movement updates the single inventory truth so the EOCC always knows what is available and where."},{"title":"Risk Assessment","icon":"fa-shield-alt","color":"#a78bfa","link":"/inform-risk","description":"INFORM subnational risk index — hazard & exposure, vulnerability and coping capacity scored for every council, on the map and by dimension."},{"title":"Stakeholder Coordination","icon":"fa-hands-helping","color":"#fb923c","link":"/m/response/stakeholders","description":"Multi-agency collaboration platform connecting government, NGOs, and international organizations."}]	json	2026-06-12 11:17:21.049571+00	2026-06-27 04:31:50.465759+00
